class SORTracker {
    TrieNode root;
    List<String> names;

    public SORTracker() {
        root = new TrieNode();
        names = new ArrayList<>();
    }

    public void add(String name, int score) {
        names.add(name);
        TrieNode node = root;
        for (char c : name.toCharArray()) {
            if (!node.children.containsKey(c)) {
                node.children.put(c, new TrieNode());
            }
            node = node.children.get(c);
        }
        node.score = score;
    }

    public String get() {
        Collections.sort(names, (a, b) -> {
            int sa = getScore(root, a);
            int sb = getScore(root, b);
            if (sa != sb) {
                return Integer.compare(sb, sa);
            } else {
                return a.compareTo(b);
            }
        });
        return names.get(names.size() - 1);
    }

    private int getScore(TrieNode node, String name) {
        TrieNode cur = node;
        for (char c : name.toCharArray()) {
            cur = cur.children.get(c);
        }
        return cur.score;
    }

    class TrieNode {
        Map<Character, TrieNode> children;
        int score;

        public TrieNode() {
            children = new HashMap<>();
            score = 0;
        }
    }
}

